**Date:** 2026-04-25
**File:** `/tmp/p15-test-Ebr1fg/app.js`
**Framework:** Express.js

---

## Summary

The file is a minimal Express app with two routes. While its small size limits the attack surface, it has **7 distinct security issues** ranging from critical to low severity. None of the OWASP Top 10 hardening basics are in place.

---

## Findings

---

### 🔴 CRITICAL — [A01] Broken Access Control: No Authentication on `/users`

**Line 11–16.** The `/users` endpoint returns PII (names and email addresses) to any unauthenticated caller with zero access control. This is a textbook A01 violation.

```js
// ❌ CURRENT — anyone on the internet can call this
app.get('/users', (req, res) => {
  res.json([{ id: 1, name: 'Alice', email: 'alice@example.com' }, ...]);
});
```

**Fix — add JWT middleware (or equivalent):**

```js
const jwt = require('jsonwebtoken');

function requireAuth(req, res, next) {
  const authHeader = req.headers.authorization;
  if (!authHeader?.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Missing or malformed token' });
  }
  try {
    req.user = jwt.verify(authHeader.slice(7), process.env.JWT_SECRET);
    next();
  } catch {
    res.status(401).json({ error: 'Invalid or expired token' });
  }
}

// ✅ Protected
app.get('/users', requireAuth, (req, res) => { ... });
```

---

### 🔴 CRITICAL — [A02] Cryptographic Failures: No HTTPS Enforcement

The app listens on plain HTTP (line 18). Credentials, tokens, and PII travel in cleartext.

**Fix:**

```js
// In production, terminate TLS at the load balancer OR:
const https = require('https');
const fs    = require('fs');

const options = {
  key:  fs.readFileSync(process.env.TLS_KEY_PATH),
  cert: fs.readFileSync(process.env.TLS_CERT_PATH),
};

https.createServer(options, app).listen(443);

// Redirect plain HTTP to HTTPS
const http = require('http');
http.createServer((req, res) => {
  res.writeHead(301, { Location: `https://${req.headers.host}${req.url}` });
  res.end();
}).listen(80);
```

---

### 🟠 HIGH — [A05] Security Misconfiguration: No Security Headers

Express ships with **`X-Powered-By: Express`** enabled by default (fingerprinting). There are also no CSP, HSTS, X-Frame-Options, or X-Content-Type-Options headers.

**Fix — add `helmet`:**

```js
const helmet = require('helmet');

app.use(helmet());                        // Sets ~14 security headers at once
app.use(helmet.hsts({ maxAge: 63072000 })); // 2-year HSTS for HTTPS sites
// helmet automatically removes X-Powered-By
```

Key headers `helmet` adds: `Content-Security-Policy`, `Strict-Transport-Security`, `X-Frame-Options: SAMEORIGIN`, `X-Content-Type-Options: nosniff`, `Referrer-Policy`.

---

### 🟠 HIGH — [A05] Security Misconfiguration: No CORS Policy

No CORS policy is defined. This means browsers apply the *same-origin* default, but no explicit policy protects against misconfigured reverse proxies or future `credentials: 'include'` calls.

**Fix:**

```js
const cors = require('cors');

app.use(cors({
  origin: process.env.ALLOWED_ORIGINS?.split(',') ?? [],  // explicit whitelist
  methods: ['GET'],                                        // restrict to what's needed
  allowedHeaders: ['Authorization', 'Content-Type'],
  credentials: true,
  maxAge: 86400,
}));
```

---

### 🟠 HIGH — [A09] Security Logging & Monitoring Failures: No Request Logging

There is no logging of requests, errors, or security events. Without logs, intrusion detection and incident response are impossible.

**Fix:**

```js
const morgan = require('morgan');

// Structured JSON logs (machine-readable for SIEM tools)
app.use(morgan('combined'));

// Global error handler — prevents Express from leaking stack traces
app.use((err, req, res, next) => {
  console.error({ 
    msg: err.message, 
    url: req.url, 
    method: req.method, 
    ip: req.ip 
  });
  res.status(500).json({ error: 'Internal server error' }); // never send err.stack
});
```

---

### 🟡 MEDIUM — [A04] Insecure Design: No Rate Limiting

No rate limiting is present. The `/users` endpoint (and any future auth endpoints) are vulnerable to enumeration, credential stuffing, and denial-of-service.

**Fix:**

```js
const rateLimit = require('express-rate-limit');

const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});

app.use('/api/', apiLimiter); // or apply globally with app.use(apiLimiter)
```

---

### 🟡 MEDIUM — [A05] Misconfiguration: Hardcoded Port & No Env Config

Port `3000` is hardcoded (line 18). Configuration that varies between environments (port, secrets, DB strings) must come from environment variables, never source code.

```js
// ❌ CURRENT
app.listen(3000, ...);

// ✅ FIX
const PORT = parseInt(process.env.PORT ?? '3000', 10);
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
```

---

### 🟢 LOW — [A03] Injection Risk: No Body Parser / Payload Size Limits

The app has no body parser configured. If `express.json()` or `express.urlencoded()` is added later without a size limit, it opens the door to payload-based DoS.

**Fix — add this proactively before any body-parsing middleware:**

```js
app.use(express.json({ limit: '10kb' }));           // reject large JSON bodies
app.use(express.urlencoded({ extended: false, limit: '10kb' }));
```

---

## Hardened `app.js` — Combined Fix

```js
'use strict';

const express   = require('express');
const helmet    = require('helmet');
const cors      = require('cors');
const morgan    = require('morgan');
const rateLimit = require('express-rate-limit');
const jwt       = require('jsonwebtoken');

const app  = express();
const PORT = parseInt(process.env.PORT ?? '3000', 10);

// ── Security headers ────────────────────────────────────────────────────────
app.use(helmet());
app.use(helmet.hsts({ maxAge: 63072000 }));

// ── CORS ────────────────────────────────────────────────────────────────────
app.use(cors({
  origin:         process.env.ALLOWED_ORIGINS?.split(',') ?? [],
  methods:        ['GET'],
  allowedHeaders: ['Authorization', 'Content-Type'],
  credentials:    true,
}));

// ── Logging ─────────────────────────────────────────────────────────────────
app.use(morgan('combined'));

// ── Rate limiting ───────────────────────────────────────────────────────────
app.use(rateLimit({ windowMs: 15 * 60 * 1000, max: 100, standardHeaders: true }));

// ── Body parsing with size limits ───────────────────────────────────────────
app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));

// ── Auth middleware ─────────────────────────────────────────────────────────
function requireAuth(req, res, next) {
  const authHeader = req.headers.authorization;
  if (!authHeader?.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  try {
    req.user = jwt.verify(authHeader.slice(7), process.env.JWT_SECRET);
    next();
  } catch {
    res.status(401).json({ error: 'Invalid or expired token' });
  }
}

// ── Routes ──────────────────────────────────────────────────────────────────
app.get('/health', (req, res) => {
  res.json({ status: 'ok' }); // omit timestamp to reduce fingerprinting
});

app.get('/users', requireAuth, (req, res) => {
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob',   email: 'bob@example.com'   },
  ]);
});

// ── Global error handler (must be last) ─────────────────────────────────────
app.use((err, req, res, _next) => {
  console.error({ msg: err.message, url: req.url, ip: req.ip });
  res.status(500).json({ error: 'Internal server error' });
});

app.listen(PORT, () => console.log(`Server running on port ${PORT}`));

module.exports = app;
```

**Required `npm install`:**
```bash
npm install helmet cors morgan express-rate-limit jsonwebtoken
```

