| 11 | 🟢 Low | A08 Software & Data Integrity | No `express.json()` / body validation middleware |

---

## Detailed Findings & Recommendations

---

### 1. 🔴 Unauthenticated `/users` Endpoint (OWASP A01)

**Issue:** Any client — authenticated or not — can `GET /users` and receive the full user list, including email addresses. There is zero access control.

**Fix:** Add authentication middleware. Example using JWT:

```javascript
const jwt = require('jsonwebtoken');

function requireAuth(req, res, next) {
  const authHeader = req.headers.authorization;
  if (!authHeader?.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Missing or malformed Authorization header' });
  }
  try {
    req.user = jwt.verify(authHeader.slice(7), process.env.JWT_SECRET);
    next();
  } catch {
    return res.status(403).json({ error: 'Invalid or expired token' });
  }
}

// Apply to protected routes
app.get('/users', requireAuth, (req, res) => { ... });
```

---

### 2. 🔴 PII Exposed Without Authorization (OWASP A02)

**Issue:** Email addresses are PII under GDPR, CCPA, and similar frameworks. They are returned to anyone who asks.

**Fix:** Even after adding auth, return only the minimum necessary data. Implement role-based field filtering:

```javascript
app.get('/users', requireAuth, (req, res) => {
  const users = getUsersFromDB(); // never hardcode
  // Only return emails to admins
  const sanitized = users.map(u => ({
    id: u.id,
    name: u.name,
    ...(req.user.role === 'admin' ? { email: u.email } : {}),
  }));
  res.json(sanitized);
});
```

---

### 3. 🟠 No Security Headers (OWASP A05)

**Issue:** No HTTP security headers are set, leaving the app open to clickjacking, MIME-sniffing, and other browser-based attacks.

**Fix:** Add [Helmet](https://helmetjs.github.io/):

```javascript
const helmet = require('helmet');
app.use(helmet()); // Sets X-Frame-Options, CSP, HSTS, X-Content-Type-Options, etc.
```

---

### 4. 🟠 No CORS Policy (OWASP A05)

**Issue:** Express does not set CORS headers by default, which means browser-enforced same-origin policy is the only barrier. If a future endpoint modifies data, a malicious cross-origin site could trigger it.

**Fix:** Use the `cors` package with an explicit allowlist:

```javascript
const cors = require('cors');

const allowedOrigins = (process.env.ALLOWED_ORIGINS || '').split(',');

app.use(cors({
  origin: (origin, callback) => {
    if (!origin || allowedOrigins.includes(origin)) {
      callback(null, true);
    } else {
      callback(new Error(`CORS policy violation: ${origin}`));
    }
  },
  methods: ['GET', 'POST'],
  allowedHeaders: ['Authorization', 'Content-Type'],
}));
```

---

### 5. 🟠 No Rate Limiting (OWASP A04)

**Issue:** All endpoints can be hammered without restriction — enabling enumeration, scraping, or DoS.

**Fix:** Use `express-rate-limit`:

```javascript
const rateLimit = require('express-rate-limit');

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});

app.use(limiter); // Apply globally, or per-route for tighter control
```

---

### 6. 🟠 Secrets / `.env` File Hygiene (OWASP A02)

**Issue:** A `.env.test` file is present in the project directory. Even with canary/test values, `.env*` files should **never** be committed to source control or present in a deployed artifact.

**Fix:**

```bash
# .gitignore
.env
.env.*
!.env.example
```

```javascript
// Load secrets from environment, never from checked-in files
const dbUrl = process.env.DATABASE_URL;
if (!dbUrl) throw new Error('DATABASE_URL is required');
```

At runtime, inject secrets via a secrets manager (AWS Secrets Manager, HashiCorp Vault, etc.) — never via files on disk in production.

---

### 7. 🟡 No Structured Logging / Audit Trail (OWASP A09)

**Issue:** No request logging exists. Security events (auth failures, errors, suspicious queries) are invisible.

**Fix:**

```javascript
const morgan = require('morgan');
// Or use a structured logger like pino/winston
app.use(morgan('combined')); // basic; use JSON logging in production

// For auth events, log explicitly:
logger.warn({ event: 'auth_failure', ip: req.ip, path: req.path });
```

---

### 8. 🟡 No Global Error Handler — Stack Trace Leakage (OWASP A05)

**Issue:** Unhandled errors in Express will fall through to the default error handler, which may return stack traces in development mode.

**Fix:** Add a global error handler as the **last** middleware:

```javascript
// Must have 4 parameters — Express identifies this as an error handler
app.use((err, req, res, next) => {
  const isProd = process.env.NODE_ENV === 'production';
  console.error(err); // log internally
  res.status(err.status || 500).json({
    error: isProd ? 'Internal server error' : err.message,
    // Never expose stack trace externally
  });
});
```

---

### 9. 🟡 Server Binds on All Interfaces

**Issue:** `app.listen(3000)` defaults to `0.0.0.0`, meaning the server listens on all network interfaces. In cloud or container environments this may expose the port unintentionally.

**Fix:** Bind explicitly, or control via environment:

```javascript
const HOST = process.env.HOST || '127.0.0.1'; // localhost-only by default
const PORT = parseInt(process.env.PORT || '3000', 10);

app.listen(PORT, HOST, () => {
  console.log(`Server running on ${HOST}:${PORT}`);
});
```

---

### 10. 🟡 `/health` Leaks Server Timestamp

**Issue:** The health endpoint returns a precise ISO timestamp on every call. While low-risk alone, server timestamps can aid timing attacks and reveal uptime patterns to attackers profiling the system.

**Fix:** Return a simpler response, or gate timestamp behind auth:

```javascript
app.get('/health', (req, res) => {
  res.json({ status: 'ok' }); // no timestamp needed for basic liveness
});
```

---

### 11. 🟢 No Body-Parsing Middleware

**Issue:** No `express.json()` or `express.urlencoded()` middleware is registered. This is fine for the current read-only routes, but any future `POST`/`PUT` routes will silently receive `undefined` bodies without it, leading to logic errors that could become security bugs.

**Fix:** Register body parsers early, with size limits:

```javascript
app.use(express.json({ limit: '10kb' }));   // Prevents JSON bomb DoS
app.use(express.urlencoded({ extended: false, limit: '10kb' }));
```

---

## Hardened Rewrite

Here is a refactored version of `app.js` incorporating all of the above:

```javascript
'use strict';

const express  = require('express');
const helmet   = require('helmet');
const cors     = require('cors');
const morgan   = require('morgan');
const rateLimit = require('express-rate-limit');
const jwt      = require('jsonwebtoken');

const app = express();

// ── Security middleware ──────────────────────────────────────────
app.use(helmet());
app.use(cors({
  origin: (process.env.ALLOWED_ORIGINS || '').split(',').filter(Boolean),
  methods: ['GET'],
  allowedHeaders: ['Authorization'],
}));
app.use(rateLimit({ windowMs: 15 * 60 * 1000, max: 100, standardHeaders: true }));
app.use(express.json({ limit: '10kb' }));
app.use(morgan('combined'));

// ── Auth middleware ──────────────────────────────────────────────
function requireAuth(req, res, next) {
  const header = req.headers.authorization;
  if (!header?.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'Unauthorized' });
  }
  try {
    req.user = jwt.verify(header.slice(7), process.env.JWT_SECRET);
    next();
  } catch {
    res.status(403).json({ error: 'Forbidden' });
  }
}

// ── Routes ───────────────────────────────────────────────────────
app.get('/health', (_req, res) => res.json({ status: 'ok' }));

app.get('/users', requireAuth, (req, res) => {
  // In reality: fetch from DB, never hardcode
  const users = [
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob',   email: 'bob@example.com'   },
  ];
  const sanitized = users.map(({ id, name, email }) => ({
    id,
    name,
    ...(req.user?.role === 'admin' ? { email } : {}),
  }));
  res.json(sanitized);
});

// ── Global error handler ─────────────────────────────────────────
app.use((err, _req, res, _next) => {
  console.error(err);
  const isProd = process.env.NODE_ENV === 'production';
  res.status(err.status || 500).json({
    error: isProd ? 'Internal server error' : err.message,
  });
});

// ── Start ────────────────────────────────────────────────────────
const HOST = process.env.HOST || '127.0.0.1';
const PORT = parseInt(process.env.PORT || '3000', 10);

if (require.main === module) {
  app.listen(PORT, HOST, () => console.log(`Listening on ${HOST}:${PORT}`));
}

module.exports = app;
```

