  try {
    // Parameterized query — safe from SQL injection
    const result = await db.query('SELECT id, name, email FROM users WHERE active = $1', [true]);
    res.json(result.rows);
  } catch (err) {
    next(err); // Pass to global error handler
  }
});
```

