  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    ...
  ]);
});
```

**Recommendation:** Protect sensitive routes with authentication middleware. Example using JWTs:

```js
const jwt = require('jsonwebtoken');

function requireAuth(req, res, next) {
  const token = req.headers.authorization?.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'Unauthorized' });

  try {
    req.user = jwt.verify(token, process.env.JWT_SECRET);
    next();
  } catch {
    return res.status(403).json({ error: 'Invalid or expired token' });
  }
}

// Apply to protected routes
app.get('/users', requireAuth, (req, res) => { ... });
```

---

### 2. Security Misconfiguration (OWASP A05) — Missing Security Headers

Express, by default, sends headers that expose server internals (e.g., `X-Powered-By: Express`) and omits headers that protect against common browser-based attacks (XSS, clickjacking, MIME sniffing, etc.).

**Recommendation:** Install and use [`helmet`](https://helmetjs.github.io/):

```bash
npm install helmet
```

```js
const helmet = require('helmet');
app.use(helmet()); // Sets X-Frame-Options, X-Content-Type-Options,
                   // Strict-Transport-Security, CSP, and more
                   // Also removes X-Powered-By header
```

---

### 3. Security Misconfiguration (OWASP A05) — No CORS Policy

Without explicit CORS configuration, cross-origin behavior is left to browser defaults. If this API is ever called from a browser, the lack of explicit CORS policy makes it easy to misconfigure later.

**Recommendation:**

```js
const cors = require('cors');

app.use(cors({
  origin: ['https://yourdomain.com'],  // Explicit allowlist, NOT '*'
  methods: ['GET', 'POST'],
  allowedHeaders: ['Authorization', 'Content-Type'],
}));
```

---

## ⚠️ High Severity Findings

### 4. Sensitive Data Exposure (OWASP A02) — PII in Hardcoded Responses

User email addresses are directly embedded in source code and returned verbatim. In production, data would come from a database — but the lack of any field filtering means sensitive fields could easily be over-exposed.

**Recommendation:** Always define explicit response projections — never return raw database objects:

```js
// Even with a DB, explicitly select fields
