res.json(users);
```

---

### 5. Identification & Authentication Failures (OWASP A07) — No Rate Limiting

There is no rate limiting on any endpoint. This makes the API vulnerable to brute-force attacks and denial-of-service.

**Recommendation:**

```js
const rateLimit = require('express-rate-limit');

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // Max 100 requests per IP per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});

app.use(limiter); // Apply globally, or per-route
```

---

### 6. Security Logging & Monitoring Failures (OWASP A09) — No Request Logging

There is no logging of requests, errors, or security events. This makes forensic analysis and incident response impossible.

**Recommendation:**

```js
const morgan = require('morgan');

// Log all requests (use 'combined' format for production)
app.use(morgan('combined'));

// Centralized error handler — prevents stack trace leakage
